access_types.code:
type tls_read_cb is access function
		(arg1 : access tls;
		arg2 : System.Address;
		arg3 : size_t;
		arg4 : System.Address) return ssize_t
	with Convention => C;

type tls_write_cb is access function
		(arg1 : access tls;
		arg2 : System.Address;
		arg3 : size_t;
		arg4 : System.Address) return ssize_t
	with Convention => C;

